import{_ as e,o as d,c as o,a2 as a}from"./chunks/framework.DvFsUg-r.js";const h=JSON.parse('{"title":"LLM 강의 임포트 — Data Model (Phase 1)","description":"","frontmatter":{"title":"LLM 강의 임포트 — Data Model (Phase 1)","feature_id":"012","created":"2026-06-03 15:10 (KST)","date":"2026-06-03T00:00:00.000Z"},"headers":[],"relativePath":"specs/012-llm-course-import/data-model.md","filePath":"specs/012-llm-course-import/data-model.md","lastUpdated":null}'),r={name:"specs/012-llm-course-import/data-model.md"};function c(s,t,l,i,n,m){return d(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="data-model-llm-main-→-vitepress-임포트" tabindex="-1">Data Model: llm-main → VitePress 임포트 <a class="header-anchor" href="#data-model-llm-main-→-vitepress-임포트" aria-label="Permalink to &quot;Data Model: llm-main → VitePress 임포트&quot;">​</a></h1><p>런타임 DB 가 아니라 <strong>변환 파이프라인이 다루는 인메모리 엔티티</strong>다.</p><h2 id="lesson-소스-강의" tabindex="-1">Lesson (소스 강의) <a class="header-anchor" href="#lesson-소스-강의" aria-label="Permalink to &quot;Lesson (소스 강의)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>필드</th><th>타입</th><th>설명</th></tr></thead><tbody><tr><td><code>srcPath</code></td><td>string</td><td><code>../llm-main/m*.md</code> 절대경로</td></tr><tr><td><code>stem</code></td><td>string</td><td>확장자 제외 파일명(<code>m101</code>, <code>m107.0</code>)</td></tr><tr><td><code>slug</code></td><td>string</td><td>URL 슬러그 = <code>stem</code> 의 <code>.</code>→<code>-</code>(<code>m107-0</code>)</td></tr><tr><td><code>orderKey</code></td><td>[number, number]</td><td><code>[major, minor]</code> 정렬키(<code>m107.0</code>→<code>[107,0]</code>)</td></tr><tr><td><code>title</code></td><td>string</td><td>첫 헤딩에서 도출(없으면 <code>Lesson &lt;stem&gt;</code>)</td></tr><tr><td><code>body</code></td><td>string</td><td>본문(변환 전 원문)</td></tr><tr><td><code>examplePath</code></td><td>string?</td><td>동명 stem 예제 <code>m*.py</code> 절대경로(있으면)</td></tr><tr><td><code>created</code></td><td>string</td><td>가상 시각 <code>YYYY-MM-DD HH:MM (KST)</code>(index 단조 증가)</td></tr><tr><td><code>date</code></td><td>string</td><td>ISO, <code>created</code> 와 동일 시각(정렬·frontmatter)</td></tr><tr><td><code>status</code></td><td>enum</td><td><code>imported</code> | <code>skipped</code>(0-byte/본문 없음)</td></tr></tbody></table><p><strong>파생 규칙</strong></p><ul><li>정렬 = <code>orderKey</code> 오름차순(major, 그다음 minor). = 학습 순서(FR-3).</li><li><code>outPath</code> = <code>blog/llm/&lt;slug&gt;.md</code>.</li><li><code>status=skipped</code> 이면 출력/인덱스/사이드바에서 제외, 리포트에 집계.</li></ul><h2 id="imageref-이미지-참조" tabindex="-1">ImageRef (이미지 참조) <a class="header-anchor" href="#imageref-이미지-참조" aria-label="Permalink to &quot;ImageRef (이미지 참조)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>필드</th><th>타입</th><th>설명</th></tr></thead><tbody><tr><td><code>rawRef</code></td><td>string</td><td>본문 원문(<code>![](app/static/101_1.png)</code>)</td></tr><tr><td><code>resolvedSrc</code></td><td>string?</td><td>실제 원본 절대경로(<code>../llm-main/static/101_1.png</code>)</td></tr><tr><td><code>outRel</code></td><td>string</td><td>출력 상대링크 <code>./assets/&lt;file&gt;</code></td></tr><tr><td><code>status</code></td><td>enum</td><td><code>copied</code> | <code>missing</code></td></tr></tbody></table><p><strong>해석 규칙</strong>: <code>app/static/&lt;file&gt;</code> 의 선행 <code>app/</code> 제거 → <code>static/&lt;file&gt;</code>. 존재하면 <code>blog/llm/assets/&lt;file&gt;</code> 로 복사(<code>copied</code>), 부재면 <code>missing</code>(링크 보존 + 리포트).</p><h2 id="examplesource-예제-소스" tabindex="-1">ExampleSource (예제 소스) <a class="header-anchor" href="#examplesource-예제-소스" aria-label="Permalink to &quot;ExampleSource (예제 소스)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>필드</th><th>타입</th><th>설명</th></tr></thead><tbody><tr><td><code>pyPath</code></td><td>string</td><td><code>../llm-main/&lt;stem&gt;.py</code></td></tr><tr><td><code>lessonStem</code></td><td>string</td><td>매핑 대상 강의 stem(1:1)</td></tr><tr><td><code>inlineStatus</code></td><td>enum</td><td><code>inlined</code> | <code>orphaned</code>(대응 강의 없음/스킵)</td></tr></tbody></table><p>본문 말미에 <code>## 전체 예제 코드</code> + <code>```python</code> 펜스로 인라인. 대응 강의가 없거나 스킵되면 <code>orphaned</code> 로 집계(게시 안 함).</p><h2 id="sidebaritem-사이드바-항목" tabindex="-1">SidebarItem (사이드바 항목) <a class="header-anchor" href="#sidebaritem-사이드바-항목" aria-label="Permalink to &quot;SidebarItem (사이드바 항목)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>필드</th><th>타입</th><th>설명</th></tr></thead><tbody><tr><td><code>text</code></td><td>string</td><td><code>mNNN · &lt;title&gt;</code>(번호 가시화)</td></tr><tr><td><code>link</code></td><td>string</td><td><code>/llm/&lt;slug&gt;</code></td></tr></tbody></table><p>→ <code>.vitepress/llm-sidebar.mts</code> 의 <code>&#39;/llm/&#39;</code> 키 배열로 직렬화. <strong>번호 오름차순 평면 목록</strong>(그룹 없음).</p><h2 id="importreport-실행-리포트" tabindex="-1">ImportReport (실행 리포트) <a class="header-anchor" href="#importreport-실행-리포트" aria-label="Permalink to &quot;ImportReport (실행 리포트)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>필드</th><th>타입</th><th>설명</th></tr></thead><tbody><tr><td><code>lessonsImported</code></td><td>number</td><td>임포트된 강의 수</td></tr><tr><td><code>lessonsSkipped</code></td><td>{stem,reason}[]</td><td>스킵(0-byte 등)</td></tr><tr><td><code>imagesCopied</code></td><td>number</td><td>복사된 이미지 수</td></tr><tr><td><code>imagesMissing</code></td><td>{lesson,ref}[]</td><td>해석 실패 이미지</td></tr><tr><td><code>examplesInlined</code></td><td>number</td><td>인라인된 예제 수</td></tr><tr><td><code>examplesOrphaned</code></td><td>{py}[]</td><td>대응 강의 없음/스킵 예제</td></tr><tr><td><code>titlesFallback</code></td><td>{stem}[]</td><td>헤딩 없어 <code>Lesson &lt;stem&gt;</code> 폴백한 강의</td></tr></tbody></table><p>콘솔 요약 + <code>blog/llm/.import-report.json</code>(git 무시) 으로 출력.</p><h2 id="상태-전이-강의-1건-파이프라인" tabindex="-1">상태 전이 (강의 1건 파이프라인) <a class="header-anchor" href="#상태-전이-강의-1건-파이프라인" aria-label="Permalink to &quot;상태 전이 (강의 1건 파이프라인)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>discover → emptyCheck → deriveTitle → parseOrderKey</span></span>\n<span class="line"><span>  → resolveImages(copy) → appendExample → sanitizeVue</span></span>\n<span class="line"><span>  → emitFrontmatter → writeOutput → indexEntry(+sidebar)</span></span></code></pre></div><p>빈 강의는 <code>emptyCheck</code> 에서 <code>skipped</code>. 그 외 실패 단계는 부분복구 + 리포트하되 <strong>전체 실행은 계속</strong>한다.</p>',21)])])}const b=e(r,[["render",c]]);export{h as __pageData,b as default};
